select s.id, s.site_id, s.name, s.code, s.storage_type, s.storage_purpose, s.github_token, s.github_owner, s.github_repo, s.github_branch, s.github_path_prefix, s.r2_account_id, s.r2_access_key, s.r2_secret_key, s.r2_bucket, s.r2_public_url, s.oss_endpoint, s.oss_access_key, s.oss_secret_key, s.oss_bucket, s.oss_region, s.base_path, s.custom_domain, s.max_file_size, s.allowed_extensions, s.is_default, s.priority, s.status, s.del_flag, s.description, s.create_by, s.create_time, s.update_by, s.update_time, c.id as category_id, c.name as category_name, c.icon as category_icon, -- 统一的可见性状态： -- 1. 自有配置（site_id = 当前网站）：优先使用关联表的is_visible（如果存在），否则使用配置本身的status -- 2. 用户默认站点（site_id = personalSiteId）： -- - 如果有关联记录（incl.id不为空），使用关联表的is_visible（忽略排除逻辑） -- - 如果没有关联记录，使用排除逻辑（有excl记录则不可见，否则可见） -- 3. 其他网站配置：使用关联表的is_visible（必须有关联记录才能访问） CASE WHEN s.site_id = #{siteId} THEN IFNULL(incl.is_visible, s.status) WHEN s.site_id = #{params.personalSiteId} THEN (CASE WHEN incl.id IS NOT NULL THEN incl.is_visible WHEN excl.id IS NULL THEN '1' ELSE '0' END) ELSE IFNULL(incl.is_visible, '0') END as is_visible, -- 关联来源标识：own(自己的) | default(默认配置) | shared(其他网站分享) CASE WHEN s.site_id = #{siteId} THEN 'own' WHEN s.site_id = #{params.personalSiteId} THEN 'default' ELSE 'shared' END as relation_source, -- 是否被排除（仅对默认配置且无关联记录时有效） CASE WHEN s.site_id = #{params.personalSiteId} AND incl.id IS NULL AND excl.id IS NOT NULL THEN 1 ELSE 0 END as is_excluded, (select count(*) from gb_site_storage_config_relations r2 where r2.storage_config_id = s.id AND r2.relation_type = 'include') as related_sites_count, (select count(*) from gb_site_storage_config_relations r3 where r3.storage_config_id = s.id AND r3.relation_type = 'exclude') as excluded_sites_count from gb_storage_configs s left join gb_categories c on s.category_id = c.id and c.del_flag = '0' -- 左连接正向关联（include） LEFT JOIN gb_site_storage_config_relations incl ON s.id = incl.storage_config_id AND incl.site_id = #{siteId} AND incl.relation_type = 'include' -- 左连接排除关联（exclude） LEFT JOIN gb_site_storage_config_relations excl ON s.id = excl.storage_config_id AND excl.site_id = #{siteId} AND excl.relation_type = 'exclude'
s.del_flag = '0'
AND ( s.site_id = #{siteId}
OR s.site_id = #{params.personalSiteId}
OR (s.site_id != #{siteId}
AND s.site_id != #{params.personalSiteId}
AND incl.id IS NOT NULL) ) and s.name like concat('%', #{name}, '%') and s.storage_type = #{storageType} and s.category_id = #{categoryId} and s.is_default = #{isDefault} and s.status = #{status}
order by s.priority asc, s.create_time desc

select s.*, 
       c.id as category_id,
       c.name as category_name,
       c.icon as category_icon,
       (select count(*) from gb_site_storage_config_relations r where r.storage_config_id = s.id AND r.relation_type = 'include') as related_sites_count,
       (select count(*) from gb_site_storage_config_relations r where r.storage_config_id = s.id AND r.relation_type = 'exclude') as excluded_sites_count
from gb_storage_configs s
left join gb_categories c on s.category_id = c.id and c.del_flag = '0'

    s.del_flag = '0'



            and (s.site_id = #{siteId} OR s.site_id = #{params.personalSiteId})



            and s.site_id = #{siteId}



            and s.site_id = #{params.personalSiteId}


            and 1 = 0


     and s.name like concat('%', #{name}, '%')
     and s.storage_type = #{storageType}
     and s.category_id = #{categoryId}
     and s.is_default = #{isDefault}
     and s.status = #{status}

order by s.priority asc, s.create_time desc

