update gb_storage_configs
site_id = #{siteId}, name = #{name}, code = #{code}, storage_type = #{storageType}, storage_purpose = #{storagePurpose}, category_id = #{categoryId}, github_token = #{githubToken}, github_owner = #{githubOwner}, github_repo = #{githubRepo}, github_branch = #{githubBranch}, github_path_prefix = #{githubPathPrefix}, r2_account_id = #{r2AccountId}, r2_access_key = #{r2AccessKey}, r2_secret_key = #{r2SecretKey}, r2_bucket = #{r2Bucket}, r2_public_url = #{r2PublicUrl}, oss_endpoint = #{ossEndpoint}, oss_access_key = #{ossAccessKey}, oss_secret_key = #{ossSecretKey}, oss_bucket = #{ossBucket}, oss_region = #{ossRegion}, base_path = #{basePath}, custom_domain = #{customDomain}, max_file_size = #{maxFileSize}, allowed_extensions = #{allowedExtensions}, is_default = #{isDefault}, priority = #{priority}, status = #{status}, description = #{description}, update_by = #{updateBy}, update_time = #{updateTime},
